FROM "Users" u, "Groups" g
WHERE u."Email" = 'usnmzozge@gmail.com' AND g."Name" = 'İstatistik 2026 Online'
  AND NOT EXISTS (SELECT 1 FROM "GroupMembers" gm WHERE gm."GroupId" = g."Id" AND gm."UserId" = u."Id");
